from typing import List

class Solution:
	def pop(self, n: List[int]) -> int:
		if len(n) == 0:
			return -1
		return n.pop()

if __name__ == '__main__':
	# Read input from STDIN
	n = list(map(int, input().split()))
	size = int(input())
	for i in range(size):
		print(Solution().pop(n))
